// Paso 1: obtener G (generación) desde SUI / datos.gov.co / XM.
// SUI publica la tarifa CU y sus componentes en su portal.
// URL dataset SUI componentes tarifarios:
// https://www.sui.gov.co/web/energia/tarifas-energia-electrica
// Dataset open data: datos.gov.co tiene el dataset de tarifas por OR.
//
// Estrategia:
// 1) Intentar datos.gov.co (dataset tarifas SUI - energy)
// 2) Fallback: calcular G desde precio bolsa XM (proxy adecuado)
// 3) Devolver componentes inferidos actualizados para cada OR

// Primero intentamos el dataset de tarifas de datos.gov.co.
// El dataset 'tx74-hte9' contiene tarifas de energía eléctrica por empresa.
const fetchSUI = async () => {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.datos.gov.co/resource/tx74-hte9.json',
    qs: {
      '$limit': '200',
      '$order': 'anio DESC, mes DESC',
      '$where': "sector='RESIDENCIAL' AND estrato='4'",
    },
    headers: { 'User-Agent': 'alebas-cotizador/1.0', 'Accept': 'application/json' },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    json: true,
  });
  if (r.statusCode !== 200) throw new Error(`SUI datos.gov.co HTTP ${r.statusCode}`);
  const rows = Array.isArray(r.body) ? r.body : [];
  if (!rows.length) throw new Error('SUI: sin registros');
  return rows;
};

// Fallback: XM precio bolsa → aproximar G
const fetchXMSpot = async () => {
  const end = new Date(Date.now() - 24*60*60*1000);
  const start = new Date(end.getTime() - 30*24*60*60*1000);
  const isoDate = d => d.toISOString().slice(0,10);
  const candidates = [
    { path: '/hourly', MetricId: 'Preciobols',   Entity: 'Sistema' },
    { path: '/hourly', MetricId: 'PrecBolsNal',  Entity: 'Sistema' },
    { path: '/hourly', MetricId: 'Bolsa',        Entity: 'Sistema' },
  ];
  for (const c of candidates) {
    try {
      const body = { MetricId: c.MetricId, StartDate: isoDate(start), EndDate: isoDate(end) };
      if (c.Entity) body.Entity = c.Entity;
      const r = await this.helpers.httpRequest({
        method: 'POST',
        url: `https://servapibi.xm.com.co${c.path}`,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
        returnFullResponse: true,
        ignoreHttpStatusErrors: true,
      });
      if (r.statusCode >= 400) continue;
      const j = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
      const vals = [];
      const walk = (n) => { if (!n) return; if (Array.isArray(n)) { n.forEach(walk); return; } if (typeof n === 'object') { for (const [k,v] of Object.entries(n)) { if (/^(Hour|Hora|Value)\d{0,2}$/i.test(k) && Number.isFinite(Number(v)) && Number(v)>0) vals.push(Number(v)); else if (typeof v==='object') walk(v); } } };
      walk(j);
      if (vals.length) return vals.reduce((s,v)=>s+v,0)/vals.length; // COP/MWh
    } catch { continue; }
  }
  return null;
};

const results = { source: [], updatedOperators: 0, components: null, errors: [] };

// Intentar SUI
let suiRows = null;
try {
  suiRows = await fetchSUI();
  results.source.push('SUI datos.gov.co');
} catch (e) {
  results.errors.push(`SUI: ${e.message}`);
}

// Intentar XM bolsa para G
let gCopMwh = null;
try {
  gCopMwh = await fetchXMSpot();
  if (gCopMwh) results.source.push('XM bolsa');
} catch (e) {
  results.errors.push(`XM: ${e.message}`);
}

// Construir componentes actualizados
// Si tenemos SUI, parsear. Si no, usar G de XM + fracciones fijas para T/D/Cv/PR/R.
const G_FRAC = 0.52; const T_FRAC = 0.08; const D_FRAC = 0.22; const Cv_FRAC = 0.05; const PR_FRAC = 0.08; const R_FRAC = 0.05;

if (suiRows && suiRows.length) {
  // Parsear SUI: extraer tarifa CU y componentes si están presentes
  // Columnas típicas: empresa, anio, mes, cargo_g, cargo_t, cargo_d, cargo_cv, cargo_pr, cargo_r, cu
  const COMPONENT_MAP = [
    ['G',  ['cargo_g','generacion','g_kwh','g']],
    ['T',  ['cargo_t','transmision','t_kwh','t']],
    ['D',  ['cargo_d','distribucion','d_kwh','d']],
    ['Cv', ['cargo_cv','comercializacion','cv_kwh','cv']],
    ['PR', ['cargo_pr','perdidas','pr_kwh','pr']],
    ['R',  ['cargo_r','restricciones','r_kwh','r']],
    ['CU', ['cargo_total','cu','tarifa','tarifa_cu','cu_kwh']],
  ];
  const grouped = {};
  for (const row of suiRows) {
    const empresa = (row.empresa || row.operador || row.nombre_empresa || '').toString().trim();
    if (!empresa) continue;
    if (!grouped[empresa]) grouped[empresa] = [];
    grouped[empresa].push(row);
  }
  const parsed = {};
  for (const [emp, rows] of Object.entries(grouped)) {
    const latest = rows[0]; // ya ordenado DESC
    const comp = {};
    for (const [key, aliases] of COMPONENT_MAP) {
      for (const alias of aliases) {
        const v = parseFloat(latest[alias]);
        if (Number.isFinite(v) && v > 0) { comp[key] = v; break; }
      }
    }
    if (comp.CU && Object.keys(comp).length >= 3) {
      parsed[emp] = comp;
    }
  }
  if (Object.keys(parsed).length) {
    results.components = parsed;
    results.source.push('SUI componentes');
  }
}

// Si SUI no dio componentes, usar G de XM + fracciones para CU estimada
if (!results.components && gCopMwh) {
  const G_kwh = gCopMwh / 1000;
  // Invertir: si G = 52% de CU, entonces CU = G / 0.52
  const CU_est = G_kwh / G_FRAC;
  results.components = {
    __default__: {
      G:  Math.round(G_kwh),
      T:  Math.round(CU_est * T_FRAC),
      D:  Math.round(CU_est * D_FRAC),
      Cv: Math.round(CU_est * Cv_FRAC),
      PR: Math.round(CU_est * PR_FRAC),
      R:  Math.round(CU_est * R_FRAC),
      CU: Math.round(CU_est),
      derivedFrom: 'XM bolsa',
    }
  };
}

results.syncedAt = new Date().toISOString();
return [{ json: results }];

const sync = $('Obtener tarifas (SUI + XM)').first().json;
const saved = $input.first().json;
return [{ json: {
  ok: true,
  message: 'Tarifas sincronizadas correctamente',
  source: sync.source,
  components: sync.components?.__default__ ?? null,
  errors: sync.errors,
  syncedAt: sync.syncedAt,
} }];
